import React, { useState, useEffect } from "react";

export default function Home() {
  const [gas, setGas] = useState(430);
  const [tds, setTDS] = useState(300);
  const [temp, setTemp] = useState(27.5);
  const [ph, setPH] = useState(6.8);
  const [red, setRed] = useState(120);
  const [green, setGreen] = useState(220);
  const [blue, setBlue] = useState(85);

  useEffect(() => {
    const interval = setInterval(() => {
      setRed(Math.floor(Math.random() * 256));
      setGreen(Math.floor(Math.random() * 256));
      setBlue(Math.floor(Math.random() * 256));
      setGas(Math.floor(Math.random() * 600));
      setTDS(Math.floor(Math.random() * 600));
      setTemp((Math.random() * 10 + 25).toFixed(1));
      setPH((Math.random() * 4 + 4.5).toFixed(2));
    }, 4000);

    return () => clearInterval(interval);
  }, []);

  const font = "Times New Roman, serif";

  const cardStyle = {
    fontFamily: font,
    backgroundColor: "#ffffffaa",
    backdropFilter: "blur(5px)",
    border: "2px solid #dcdcdc",
    borderRadius: "15px",
    padding: "20px",
    width: "100%",
    maxWidth: "400px",
    margin: "20px auto",
    boxShadow: "0 6px 12px rgba(0,0,0,0.1)",
  };

  const labelStyle = {
    fontWeight: "bold",
    fontSize: "20px",
    color: "#333",
    marginBottom: "5px",
  };

  const valueBox = {
    backgroundColor: "#f1f1f1",
    padding: "12px 20px",
    borderRadius: "10px",
    fontWeight: "bold",
    fontSize: "22px",
    textAlign: "center",
    marginBottom: "10px",
    border: "2px solid #ccc",
  };

  const rangeText = {
    fontSize: "16px",
    fontWeight: "normal",
    marginBottom: "5px",
    color: "#666",
  };

  const badge = (status) => ({
    padding: "6px 14px",
    borderRadius: "20px",
    fontWeight: "bold",
    fontSize: "15px",
    color: "#fff",
    backgroundColor: status === "Good" ? "#28a745" : "#dc3545",
    display: "inline-block",
  });

  const sectionHeader = {
    fontFamily: font,
    fontSize: "30px",
    fontWeight: "bold",
    textAlign: "center",
    margin: "30px 0 10px",
    color: "#4b0082",
  };

  const containerStyle = {
    fontFamily: font,
    background: "linear-gradient(to bottom right, #f5f7fa, #d6e1f0)",
    minHeight: "100vh",
    padding: "20px",
  };

  // Safety conditions
  const statusChecks = {
    gas: { value: gas, min: 0, max: 350 },
    tds: { value: tds, min: 0, max: 300 },
    temp: { value: temp, min: 20, max: 35 },
    ph: { value: ph, min: 6.5, max: 8.5 },
    red: { value: red, min: 100, max: 255 },
    green: { value: green, min: 100, max: 255 },
    blue: { value: blue, min: 100, max: 255 },
  };

  const getStatus = (sensor) => {
    const { value, min, max } = statusChecks[sensor];
    return value >= min && value <= max ? "Good" : "Bad";
  };

  return (
    <div style={containerStyle}>
      <h1 style={sectionHeader}>🧪 FoodScan Sensor Dashboard</h1>

      {/* GAS */}
      <div style={cardStyle}>
        <div style={labelStyle}>🌫️ Gas Sensor</div>
        <div style={valueBox}>{gas} ppm</div>
        <div style={rangeText}>Safe Range: ≤ 350 ppm</div>
        <span style={badge(getStatus("gas"))}>{getStatus("gas")}</span>
      </div>

      {/* TDS */}
      <div style={cardStyle}>
        <div style={labelStyle}>💧 TDS Sensor</div>
        <div style={valueBox}>{tds} ppm</div>
        <div style={rangeText}>Safe Range: ≤ 300 ppm</div>
        <span style={badge(getStatus("tds"))}>{getStatus("tds")}</span>
      </div>

      {/* TEMPERATURE */}
      <div style={cardStyle}>
        <div style={labelStyle}>🌡️ Temperature</div>
        <div style={valueBox}>{temp} °C</div>
        <div style={rangeText}>Safe Range: 20°C – 35°C</div>
        <span style={badge(getStatus("temp"))}>{getStatus("temp")}</span>
      </div>

      {/* pH SENSOR */}
      <div style={cardStyle}>
        <div style={labelStyle}>🧪 pH Sensor</div>
        <div style={valueBox}>{ph}</div>
        <div style={rangeText}>Safe Range: 6.5 – 8.5</div>
        <span style={badge(getStatus("ph"))}>{getStatus("ph")}</span>
      </div>

      {/* RED */}
      <div style={cardStyle}>
        <div style={labelStyle}>🔴 Red Value</div>
        <div style={valueBox}>{red}</div>
        <div style={rangeText}>Safe Range: ≥ 100</div>
        <span style={badge(getStatus("red"))}>{getStatus("red")}</span>
      </div>

      {/* GREEN */}
      <div style={cardStyle}>
        <div style={labelStyle}>🟢 Green Value</div>
        <div style={valueBox}>{green}</div>
        <div style={rangeText}>Safe Range: ≥ 100</div>
        <span style={badge(getStatus("green"))}>{getStatus("green")}</span>
      </div>

      {/* BLUE */}
      <div style={cardStyle}>
        <div style={labelStyle}>🔵 Blue Value</div>
        <div style={valueBox}>{blue}</div>
        <div style={rangeText}>Safe Range: ≥ 100</div>
        <span style={badge(getStatus("blue"))}>{getStatus("blue")}</span>
      </div>
    </div>
  );
}
